# Split by " - AAU HPC" to get segments (each segment is one row, title is the part after last path segment)
segments = data.split(" - AAU HPC")
rows = []
for i, seg in enumerate(segments):
    seg = seg.strip()
    if not seg:
        continue
    # Remove trailing #n rank and store it
    rank = ""
    m = re.search(r'\s#(\d+)\s*$', seg)
    if m:
        rank = "#" + m.group(1)
        seg = seg[:m.start()].strip()
    # Remove leading " #n " (rank from previous row) e.g. " #12 753 +1058% ..." -> "753 +1058% ..."
    seg = re.sub(r'^\s*#\d+\s+', '', seg).strip()
    # Remove leading "39 " when it's line number: "39 76 +744%" -> "76 +744%", but keep "39 764" (39764)
    if re.match(r'^39 \d{1,2}(?!\d)', seg):
        seg = seg[3:].strip()
    # Parse: views (digits with optional space), change (+N%, -N%, (new)), path (/...), title
    # Change can be +802%, -32%, (new), or +N%
    change_match = re.search(r'(\+\d+%|[\u2013\-]\d+%|\(\s*new\s*\))', seg)
    if not change_match:
        continue
    change = change_match.group(1).strip().replace("\u2013", "-")  # en-dash to hyphen
    before_change = seg[:change_match.start()].strip()
    after_change = seg[change_match.end():].strip()
    # before_change is the views number (may have space as thousands sep, e.g. "2 967" -> 2967)
    views = before_change.replace(" ", "").strip()
    if not views.isdigit():
        views = ""
    # after_change: path + title. Path starts with /
    path_match = re.match(r'(/\S*)\s*(.*)', after_change)
    if path_match:
        path = path_match.group(1)
        title = path_match.group(2).strip() if path_match.group(2) else path
    else:
        path = ""
        title = after_change
    if not path.startswith("/"):
        continue
    rows.append((rank or str(i+1), views, change, path, title))

# Build markdown table
out = "| # | Views | Change | Path | Page |\n"
out += "|---|-------|--------|------|------|\n"
for r in rows:
    rank, views, change, path, title = r
    # Escape pipe in title
    title_esc = title.replace("|", "\\|")
    out += f"| {rank} | {views} | {change} | {path} | {title_esc} |\n"

with open("docs/page-views-table.md", "w", encoding="utf-8") as f:
    f.write("# Page views (HPC site)\n\n")
    f.write(out)
print(out)
